{"code": "# Let's research more MCPs systematically
import subprocess, json

# Check what MCPs are most valuable for our org
searches = {
    "slack": "mcp-server slack",
    "notion": "mcp-server notion",
    "grafana": "mcp-server grafana",
    "google": "mcp-server google",
    "vercel": "mcp-server vercel",
    "brave": "brave-search",
    "docker": "docker mcp",
    "figma": "figma mcp",
    "you.com": "you.com mcp",
    "exa": "exa mcp",
}

results = {}
for name, query in searches.items():
    r = subprocess.run(
        ["npm", "search", query],
        capture_output=True, text=True, timeout=15
    )
    lines = [l for l in r.stdout.strip().split('\n') if l.strip()][:2]
    results[name] = lines

for name, lines in results.items():
    print(f"--- {name} ---")
    for l in lines:
        print(f"  {l}")
    if not lines:
        print("  (none found)")
"}

